import subprocess
import pytest

def run(code: str) -> dict:
    return run_in_container(code, timeout=10)

def test_basic_python_runs():
    r = run("print(2 + 2)")
    assert r["error"] is None
    assert "4" in r["stdout"]

def test_numpy_available():
    r = run("import numpy as np; print(np.array([1,2,3]).sum())")
    assert r["error"] is None
    assert "6" in r["stdout"]

def test_network_blocked():
    r = run("import socket; socket.create_connection(('8.8.8.8', 53), timeout=2)")
    assert r["returncode"] != 0  # should fail — network=none

def test_filesystem_read_only():
    r = run("open('/etc/shadow', 'w').write('hacked')")
    assert r["returncode"] != 0

def test_tmp_is_writable():
    r = run("open('/tmp/test.txt', 'w').write('ok'); print(open('/tmp/test.txt').read())")
    assert r["error"] is None
    assert "ok" in r["stdout"]

def test_no_shell():
    r = run("import subprocess; subprocess.run(['bash', '-c', 'echo hi'])")
    assert r["returncode"] != 0  # bash was removed from image

def test_timeout_respected():
    r = run("while True: pass", timeout=3)
    assert "timed out" in (r.get("error") or "").lower()
